{
  "name": "Smart Vocab Flip",
  "description": "A high-performance English word memorization tool using a 3D flip card interface, local storage persistence, and native text-to-speech integration for a premium learning experience."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface WordEntry {
  id: string;
  english: string;
  chinese: string;
  mastered: boolean;
}

export interface AppSettings {
  speechRate: number;
  voiceURI: string;
  hideMastered: boolean;
}

export enum ViewMode {
  LEARN = 'LEARN',
  INPUT = 'INPUT',
  SETTINGS = 'SETTINGS'
}

export const getAvailableVoices = (): SpeechSynthesisVoice[] => {
  return window.speechSynthesis.getVoices().filter(v => v.lang.startsWith('en'));
};

export const speak = (text: string, voiceURI: string, rate: number) => {
  if (!window.speechSynthesis) return;

  // Cancel any ongoing speech
  window.speechSynthesis.cancel();

  const utterance = new SpeechSynthesisUtterance(text);
  const voices = window.speechSynthesis.getVoices();
  const selectedVoice = voices.find(v => v.voiceURI === voiceURI);

  if (selectedVoice) {
    utterance.voice = selectedVoice;
  }
  utterance.rate = rate;
  utterance.lang = 'en-US';

  window.speechSynthesis.speak(utterance);
};

import React, { useState, useEffect, useCallback } from 'react';
import { Settings, Edit3, BookOpen, BrainCircuit } from 'lucide-react';
import { WordEntry, AppSettings, ViewMode } from './types';
import WordInput from './components/WordInput';
import FlashCardContainer from './components/FlashCardContainer';
import SettingsPanel from './components/SettingsPanel';

const STORAGE_KEY_WORDS = 'smart_vocab_words';
const STORAGE_KEY_SETTINGS = 'smart_vocab_settings';

const App: React.FC = () => {
  const [view, setView] = useState<ViewMode>(ViewMode.LEARN);
  const [words, setWords] = useState<WordEntry[]>([]);
  const [settings, setSettings] = useState<AppSettings>({
    speechRate: 1.0,
    voiceURI: '',
    hideMastered: false,
  });

  // Load from local storage
  useEffect(() => {
    const savedWords = localStorage.getItem(STORAGE_KEY_WORDS);
    const savedSettings = localStorage.getItem(STORAGE_KEY_SETTINGS);

    if (savedWords) setWords(JSON.parse(savedWords));
    if (savedSettings) setSettings(JSON.parse(savedSettings));

    // Warm up voices
    window.speechSynthesis.getVoices();
  }, []);

  // Save to local storage
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_WORDS, JSON.stringify(words));
  }, [words]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_SETTINGS, JSON.stringify(settings));
  }, [settings]);

  const handleUpdateWords = (newWords: WordEntry[]) => {
    setWords(newWords);
    setView(ViewMode.LEARN);
  };

  const toggleMastery = (id: string) => {
    setWords(prev => prev.map(w => w.id === id ? { ...w, mastered: !w.mastered } : w));
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-50 text-slate-900">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between sticky top-0 z-50">
        <div className="flex items-center gap-2 cursor-pointer" onClick={() => setView(ViewMode.LEARN)}>
          <div className="bg-indigo-600 p-2 rounded-xl text-white">
            <BrainCircuit size={24} />
          </div>
          <h1 className="text-xl font-bold tracking-tight text-slate-800 hidden sm:block">Smart Vocab</h1>
        </div>

        <nav className="flex items-center gap-1 sm:gap-4 bg-slate-100 p-1 rounded-full">
          <button
            onClick={() => setView(ViewMode.LEARN)}
            className={`flex items-center gap-2 px-4 py-2 rounded-full text-sm font-medium transition-all ${
              view === ViewMode.LEARN ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
            }`}
          >
            <BookOpen size={18} />
            <span className="hidden xs:inline">学习</span>
          </button>
          <button
            onClick={() => setView(ViewMode.INPUT)}
            className={`flex items-center gap-2 px-4 py-2 rounded-full text-sm font-medium transition-all ${
              view === ViewMode.INPUT ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
            }`}
          >
            <Edit3 size={18} />
            <span className="hidden xs:inline">导入</span>
          </button>
          <button
            onClick={() => setView(ViewMode.SETTINGS)}
            className={`flex items-center gap-2 px-4 py-2 rounded-full text-sm font-medium transition-all ${
              view === ViewMode.SETTINGS ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
            }`}
          >
            <Settings size={18} />
            <span className="hidden xs:inline">设置</span>
          </button>
        </nav>
      </header>

      {/* Main Content */}
      <main className="flex-1 flex flex-col items-center justify-center p-4">
        {view === ViewMode.LEARN && (
          <FlashCardContainer 
            words={words} 
            settings={settings} 
            onToggleMastery={toggleMastery}
            onGoToInput={() => setView(ViewMode.INPUT)}
          />
        )}
        {view === ViewMode.INPUT && (
          <WordInput initialWords={words} onSave={handleUpdateWords} />
        )}
        {view === ViewMode.SETTINGS && (
          <SettingsPanel settings={settings} onUpdateSettings={setSettings} />
        )}
      </main>

      <footer className="text-center py-4 text-xs text-slate-400">
        &copy; {new Date().getFullYear()} Smart Vocab Flip • 高效背词
      </footer>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Save, AlertCircle } from 'lucide-react';
import { WordEntry } from '../types';

interface WordInputProps {
  initialWords: WordEntry[];
  onSave: (words: WordEntry[]) => void;
}

const WordInput: React.FC<WordInputProps> = ({ initialWords, onSave }) => {
  const [text, setText] = useState(
    initialWords.map(w => `${w.english} - ${w.chinese.replace(/\n/g, ' | ')}`).join('\n')
  );

  const handleSave = () => {
    const lines = text.split('\n').filter(line => line.trim().length > 0);
    const newWords: WordEntry[] = lines.map((line, index) => {
      const [english, ...chineseParts] = line.split('-').map(s => s.trim());
      const chinese = chineseParts.join('-').replace(/\s*\|\s*/g, '\n');

      // Check if it already exists to preserve mastery state
      const existing = initialWords.find(w => w.english.toLowerCase() === english.toLowerCase());

      return {
        id: existing?.id || `word-${Date.now()}-${index}`,
        english: english || 'Empty',
        chinese: chinese || '无解释',
        mastered: existing?.mastered || false
      };
    });

    onSave(newWords);
  };

  return (
    <div className="w-full max-w-3xl flex flex-col gap-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="bg-white p-8 rounded-3xl shadow-xl border border-slate-100">
        <div className="flex items-center justify-between mb-6">
          <div>
            <h2 className="text-2xl font-bold text-slate-800">导入词库</h2>
            <p className="text-slate-500 text-sm mt-1">
              格式：英文单词 - 中文解释 (使用 | 换行)
            </p>
          </div>
          <button
            onClick={handleSave}
            className="flex items-center gap-2 px-6 py-3 bg-indigo-600 hover:bg-indigo-700 text-white font-semibold rounded-2xl transition-all shadow-lg shadow-indigo-200"
          >
            <Save size={20} />
            保存词库
          </button>
        </div>

        <div className="relative group">
          <textarea
            value={text}
            onChange={(e) => setText(e.target.value)}
            placeholder="例如：&#10;apple - 苹果 | 健康&#10;banana - 香蕉 | 热带水果"
            className="w-full h-96 p-6 text-lg bg-slate-50 border border-slate-200 rounded-2xl focus:ring-4 focus:ring-indigo-100 focus:border-indigo-400 outline-none transition-all resize-none font-mono"
          />
          <div className="absolute top-4 right-4 text-indigo-400 opacity-20 group-focus-within:opacity-40 transition-opacity">
            <Edit3 size={48} />
          </div>
        </div>

        <div className="mt-6 p-4 bg-indigo-50 rounded-2xl border border-indigo-100 flex items-start gap-3">
          <AlertCircle className="text-indigo-500 mt-0.5 shrink-0" size={20} />
          <p className="text-sm text-indigo-800 leading-relaxed">
            提示：每个单词占一行。点击“保存”后，系统会自动更新学习列表。若单词已存在，将保留之前的“已记住”状态。
          </p>
        </div>
      </div>
    </div>
  );
};

import { Edit3 } from 'lucide-react';
export default WordInput;

import React, { useState, useMemo } from 'react';
import { ChevronLeft, ChevronRight, PlusCircle, Filter } from 'lucide-react';
import { WordEntry, AppSettings } from '../types';
import FlashCard from './FlashCard';

interface FlashCardContainerProps {
  words: WordEntry[];
  settings: AppSettings;
  onToggleMastery: (id: string) => void;
  onGoToInput: () => void;
}

const FlashCardContainer: React.FC<FlashCardContainerProps> = ({ 
  words, 
  settings, 
  onToggleMastery,
  onGoToInput
}) => {
  const [currentIndex, setCurrentIndex] = useState(0);

  const displayWords = useMemo(() => {
    if (settings.hideMastered) {
      return words.filter(w => !w.mastered);
    }
    return words;
  }, [words, settings.hideMastered]);

  const currentWord = displayWords[currentIndex];

  const handleNext = () => {
    if (currentIndex < displayWords.length - 1) {
      setCurrentIndex(prev => prev + 1);
    } else {
      setCurrentIndex(0); // Loop back
    }
  };

  const handlePrev = () => {
    if (currentIndex > 0) {
      setCurrentIndex(prev => prev - 1);
    } else {
      setCurrentIndex(displayWords.length - 1); // Loop to end
    }
  };

  if (words.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center gap-6 py-20 animate-in fade-in zoom-in duration-500">
        <div className="w-32 h-32 bg-indigo-100 text-indigo-600 rounded-full flex items-center justify-center">
          <PlusCircle size={64} strokeWidth={1.5} />
        </div>
        <div className="text-center">
          <h2 className="text-2xl font-bold text-slate-800">词库还是空的</h2>
          <p className="text-slate-500 mt-2">点击下方按钮添加你的第一个单词吧！</p>
        </div>
        <button
          onClick={onGoToInput}
          className="px-8 py-3 bg-indigo-600 text-white rounded-2xl font-bold hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-100"
        >
          立即添加单词
        </button>
      </div>
    );
  }

  if (displayWords.length === 0) {
    return (
      <div className="text-center py-20">
        <div className="w-24 h-24 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto mb-6">
          <Filter size={48} />
        </div>
        <h2 className="text-2xl font-bold text-slate-800">太棒了！</h2>
        <p className="text-slate-500 mt-2">当前列表所有单词都已记住。前往“设置”关闭“隐藏已记住”即可查看全部。</p>
      </div>
    );
  }

  return (
    <div className="w-full max-w-4xl flex flex-col items-center gap-8 animate-in fade-in duration-700">
      <div className="w-full flex items-center justify-between px-4 sm:px-12">
        <button 
          onClick={handlePrev}
          className="p-4 bg-white hover:bg-indigo-50 text-indigo-600 rounded-full shadow-lg border border-slate-100 transition-all active:scale-95 z-10"
        >
          <ChevronLeft size={32} />
        </button>

        <div className="flex-1 max-w-lg mx-4">
          <FlashCard 
            word={currentWord} 
            settings={settings}
            onToggleMastery={() => onToggleMastery(currentWord.id)}
          />
        </div>

        <button 
          onClick={handleNext}
          className="p-4 bg-white hover:bg-indigo-50 text-indigo-600 rounded-full shadow-lg border border-slate-100 transition-all active:scale-95 z-10"
        >
          <ChevronRight size={32} />
        </button>
      </div>

      <div className="flex flex-col items-center gap-2">
        <div className="text-sm font-medium text-slate-400">
          进度: <span className="text-indigo-600 font-bold">{currentIndex + 1}</span> / {displayWords.length}
        </div>
        <div className="w-48 h-1.5 bg-slate-200 rounded-full overflow-hidden">
          <div 
            className="h-full bg-indigo-600 transition-all duration-300"
            style={{ width: `${((currentIndex + 1) / displayWords.length) * 100}%` }}
          />
        </div>
      </div>
    </div>
  );
};

export default FlashCardContainer;

import React, { useState, useEffect } from 'react';
import { Volume2, CheckCircle2, BrainCircuit } from 'lucide-react';
import { WordEntry, AppSettings } from '../types';
import { speak } from '../utils/speech';

interface FlashCardProps {
  word: WordEntry;
  settings: AppSettings;
  onToggleMastery: () => void;
}

const FlashCard: React.FC<FlashCardProps> = ({ word, settings, onToggleMastery }) => {
  // isFlipped: false = showing Side B (Chinese), true = showing Side A (English)
  const [isFlipped, setIsFlipped] = useState(false);

  // Reset flip when word changes
  useEffect(() => {
    setIsFlipped(false);
  }, [word.id]);

  const handleSpeak = (e: React.MouseEvent) => {
    e.stopPropagation();
    speak(word.english, settings.voiceURI, settings.speechRate);
  };

  return (
    <div 
      className="perspective-1000 w-full h-[450px] cursor-pointer group"
      onClick={() => setIsFlipped(!isFlipped)}
    >
      <div className={`relative w-full h-full transition-transform duration-700 preserve-3d ${isFlipped ? 'rotate-y-180' : ''}`}>

        {/* Front Side: Chinese (Initially visible as per requirement) */}
        <div className="absolute inset-0 w-full h-full backface-hidden bg-white rounded-[2.5rem] shadow-2xl border-2 border-slate-50 flex flex-col p-10 overflow-hidden">
          {/* Smart Icon Background */}
          <div className="absolute top-0 right-0 p-8 text-indigo-50 opacity-10 pointer-events-none">
            <BrainCircuit size={180} />
          </div>

          <div className="flex justify-between items-start z-10">
            <div className="bg-indigo-50 p-2 rounded-xl text-indigo-500">
              <BrainCircuit size={28} />
            </div>
            <button 
              onClick={(e) => {
                e.stopPropagation();
                onToggleMastery();
              }}
              className={`transition-colors p-1 ${word.mastered ? 'text-green-500' : 'text-slate-200 hover:text-slate-400'}`}
              title={word.mastered ? "已记住" : "标记为已记住"}
            >
              <CheckCircle2 size={32} />
            </button>
          </div>

          <div className="flex-1 flex flex-col items-center justify-center text-center px-4 z-10">
            <div className="space-y-4">
              {word.chinese.split('\n').map((line, i) => (
                <p key={i} className="text-2xl sm:text-3xl font-medium text-slate-800 leading-tight">
                  {line}
                </p>
              ))}
            </div>
          </div>

          <div className="text-center text-slate-400 text-sm font-medium z-10 animate-pulse">
            点击翻转查看英文
          </div>
        </div>

        {/* Back Side: English */}
        <div className="absolute inset-0 w-full h-full backface-hidden bg-indigo-600 rounded-[2.5rem] shadow-2xl border-2 border-indigo-500 flex flex-col p-10 rotate-y-180 text-white">
           {/* Smart Icon Background */}
           <div className="absolute top-0 right-0 p-8 text-white opacity-10 pointer-events-none">
            <BrainCircuit size={180} />
          </div>

          <div className="flex justify-between items-start z-10">
             <div className="bg-white/20 p-2 rounded-xl text-white">
              <BrainCircuit size={28} />
            </div>
            <button 
              onClick={(e) => {
                e.stopPropagation();
                onToggleMastery();
              }}
              className={`transition-colors p-1 ${word.mastered ? 'text-green-300' : 'text-white/30 hover:text-white/50'}`}
              title={word.mastered ? "已记住" : "标记为已记住"}
            >
              <CheckCircle2 size={32} />
            </button>
          </div>

          <div className="flex-1 flex flex-col items-center justify-center text-center px-4 z-10">
            <h3 className="text-5xl sm:text-6xl font-bold tracking-tight mb-8 break-all leading-tight">
              {word.english}
            </h3>

            <button
              onClick={handleSpeak}
              className="p-6 bg-white/20 hover:bg-white/30 rounded-full transition-all group/speak active:scale-90"
            >
              <Volume2 size={40} className="group-hover/speak:scale-110 transition-transform" />
            </button>
          </div>

          <div className="text-center text-indigo-100 text-sm font-medium z-10">
            点击翻转回到解释
          </div>
        </div>

      </div>
    </div>
  );
};

export default FlashCard;

import React, { useEffect, useState } from 'react';
import { Sliders, Volume2, Globe, EyeOff, BrainCircuit } from 'lucide-react';
import { AppSettings } from '../types';
import { getAvailableVoices } from '../utils/speech';

interface SettingsPanelProps {
  settings: AppSettings;
  onUpdateSettings: (settings: AppSettings) => void;
}

const SettingsPanel: React.FC<SettingsPanelProps> = ({ settings, onUpdateSettings }) => {
  const [voices, setVoices] = useState<SpeechSynthesisVoice[]>([]);

  useEffect(() => {
    const loadVoices = () => {
      const v = getAvailableVoices();
      setVoices(v);
      // Set default voice if none selected
      if (!settings.voiceURI && v.length > 0) {
        onUpdateSettings({ ...settings, voiceURI: v[0].voiceURI });
      }
    };

    loadVoices();
    window.speechSynthesis.onvoiceschanged = loadVoices;
    return () => {
      window.speechSynthesis.onvoiceschanged = null;
    };
  }, [settings, onUpdateSettings]);

  const handleChange = (key: keyof AppSettings, value: any) => {
    onUpdateSettings({ ...settings, [key]: value });
  };

  return (
    <div className="w-full max-w-2xl animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="bg-white p-10 rounded-[2.5rem] shadow-xl border border-slate-100 relative overflow-hidden">
        {/* Subtle decorative background */}
        <div className="absolute -top-24 -right-24 text-slate-50 opacity-50 pointer-events-none">
          <BrainCircuit size={400} />
        </div>

        <div className="flex items-center gap-3 mb-10 z-10 relative">
          <div className="bg-indigo-100 p-2.5 rounded-2xl text-indigo-600">
            <Sliders size={24} />
          </div>
          <h2 className="text-3xl font-bold text-slate-800 tracking-tight">全局设置</h2>
        </div>

        <div className="space-y-10 z-10 relative">
          {/* Voice Selection */}
          <section className="space-y-4">
            <div className="flex items-center gap-2 text-slate-700 font-semibold mb-2">
              <Globe size={18} className="text-indigo-500" />
              <h3>发音音色 (英文)</h3>
            </div>
            <select
              value={settings.voiceURI}
              onChange={(e) => handleChange('voiceURI', e.target.value)}
              className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-4 focus:ring-indigo-100 focus:border-indigo-400 outline-none transition-all appearance-none cursor-pointer"
            >
              {voices.length === 0 && <option>正在加载系统音色...</option>}
              {voices.map(voice => (
                <option key={voice.voiceURI} value={voice.voiceURI}>
                  {voice.name} ({voice.lang})
                </option>
              ))}
            </select>
            <p className="text-xs text-slate-400 italic">注：音色由浏览器/操作系统提供，部分平台需点击“朗读”图标后激活。</p>
          </section>

          {/* Speech Rate */}
          <section className="space-y-4">
            <div className="flex items-center justify-between mb-2">
              <div className="flex items-center gap-2 text-slate-700 font-semibold">
                <Volume2 size={18} className="text-indigo-500" />
                <h3>朗读语速</h3>
              </div>
              <span className="text-indigo-600 font-bold bg-indigo-50 px-3 py-1 rounded-full text-sm">
                {settings.speechRate.toFixed(1)}x
              </span>
            </div>
            <input
              type="range"
              min="0.5"
              max="2"
              step="0.1"
              value={settings.speechRate}
              onChange={(e) => handleChange('speechRate', parseFloat(e.target.value))}
              className="w-full h-2 bg-slate-100 rounded-lg appearance-none cursor-pointer accent-indigo-600"
            />
            <div className="flex justify-between text-xs text-slate-400 font-medium">
              <span>较慢 (0.5x)</span>
              <span>正常 (1.0x)</span>
              <span>较快 (2.0x)</span>
            </div>
          </section>

          {/* Filtering */}
          <section className="pt-4 border-t border-slate-100">
            <label className="flex items-center justify-between cursor-pointer group">
              <div className="flex items-center gap-2 text-slate-700 font-semibold">
                <EyeOff size={18} className="text-indigo-500" />
                <h3>隐藏已记住的卡片</h3>
              </div>
              <div className="relative inline-flex items-center">
                <input
                  type="checkbox"
                  checked={settings.hideMastered}
                  onChange={(e) => handleChange('hideMastered', e.target.checked)}
                  className="sr-only peer"
                />
                <div className="w-14 h-7 bg-slate-200 peer-focus:outline-none peer-focus:ring-4 peer-focus:ring-indigo-100 rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-6 after:w-6 after:transition-all peer-checked:bg-indigo-600"></div>
              </div>
            </label>
          </section>
        </div>
      </div>
    </div>
  );
};

export default SettingsPanel;

export const getAvailableVoices = (): SpeechSynthesisVoice[] => {
  if (typeof window === 'undefined' || !window.speechSynthesis) return [];
  return window.speechSynthesis.getVoices().filter(v => v.lang.startsWith('en'));
};

export const speak = (text: string, voiceURI: string, rate: number) => {
  if (typeof window === 'undefined' || !window.speechSynthesis) {
    console.warn('Speech synthesis not supported');
    return;
  }

  // Cancel any ongoing speech to prevent queuing
  window.speechSynthesis.cancel();

  const utterance = new SpeechSynthesisUtterance(text);
  const voices = window.speechSynthesis.getVoices();

  // Try to find the selected voice
  const selectedVoice = voices.find(v => v.voiceURI === voiceURI);
  if (selectedVoice) {
    utterance.voice = selectedVoice;
  } else {
    // Fallback: search for any English voice if selected one is not available
    const fallbackVoice = voices.find(v => v.lang.startsWith('en'));
    if (fallbackVoice) utterance.voice = fallbackVoice;
  }

  utterance.rate = rate;
  utterance.lang = 'en-US';

  // Some browsers (like iOS Safari) require a small delay or specific state
  // But usually calling it directly in a click handler is correct.
  window.speechSynthesis.speak(utterance);
};

import React, { useState, useEffect } from 'react';
import { Volume2, CheckCircle2, BrainCircuit } from 'lucide-react';
