import React, { useState, useEffect, useMemo } from 'react';
import ReactDOM from 'react-dom/client';
import htm from 'htm';
import * as Lucide from 'lucide-react';

// 初始化 htm (将类似 JSX 的语法绑定到 React.createElement)
const html = htm.bind(React.createElement);

// --- 1. 工具函数 (原 speech.ts) ---
const getAvailableVoices = () => {
  if (typeof window === 'undefined' || !window.speechSynthesis) return [];
  const allVoices = window.speechSynthesis.getVoices();
  const enVoices = allVoices.filter(v => v.lang.startsWith('en'));
  const premiumKeywords = ['jenny', 'microsoft ana', 'sonia', 'samantha', 'google us english', 'apple english'];
  const premiumVoices = enVoices.filter(v => premiumKeywords.some(k => v.name.toLowerCase().includes(k)));
  return premiumVoices.length > 0 ? premiumVoices : enVoices;
};

const speak = (text, voiceURI, rate) => {
  if (typeof window === 'undefined' || !window.speechSynthesis) return;
  window.speechSynthesis.cancel();
  const utterance = new SpeechSynthesisUtterance(text);
  const voices = window.speechSynthesis.getVoices();
  let selectedVoice = voices.find(v => v.voiceURI === voiceURI) || getAvailableVoices()[0];
  if (selectedVoice) utterance.voice = selectedVoice;
  utterance.rate = rate;
  utterance.lang = 'en-US';
  window.speechSynthesis.speak(utterance);
};

