const html = htm.bind(React.createElement);

/**
 * --- 1. 语音控制逻辑 (适配 Windows/iOS) ---
 */
const SpeechControl = {
  getVoices: () => {
    if (typeof window === 'undefined' || !window.speechSynthesis) return [];
    const allVoices = window.speechSynthesis.getVoices();
    // 过滤出英文语音
    const enVoices = allVoices.filter(v => v.lang.startsWith('en'));
    // 优先推荐各平台的优质语音
    const premiumKeywords = ['jenny', 'ana', 'sonia', 'samantha', 'google us', 'apple', 'premium'];
    const premium = enVoices.filter(v => premiumKeywords.some(k => v.name.toLowerCase().includes(k)));
    return premium.length > 0 ? premium : enVoices;
  },

  speak: (text, voiceURI, rate) => {
    if (!window.speechSynthesis) return;
    window.speechSynthesis.cancel();

    const utterance = new SpeechSynthesisUtterance(text);
    const voices = window.speechSynthesis.getVoices();
    const selectedVoice = voices.find(v => v.voiceURI === voiceURI);

    if (selectedVoice) {
      utterance.voice = selectedVoice;
      utterance.lang = selectedVoice.lang;
    } else {
      utterance.lang = 'en-US';
    }

    utterance.rate = rate || 1.0;
    utterance.pitch = 1.0;

    // iOS Safari 必须在用户交互触发的调用栈中启动
    window.speechSynthesis.speak(utterance);
  }
};

/**
 * --- 2. 单词卡片组件 ---
 */
const FlashCard = ({ word, settings, onToggleMastery }) => {
