    const len = text.length;
    if (len < 12) return 'text-5xl sm:text-7xl';
    if (len < 22) return 'text-4xl sm:text-5xl';
    return 'text-2xl sm:text-3xl';
  };

  return html`
    <div className="perspective-1000 w-full card-height group select-none relative">
      <div className=${`relative w-full h-full transition-transform duration-700 preserve-3d ${isFlipped ? 'rotate-y-180' : ''}`}>

        <!-- 正面: 中文 (默认) -->
        <div onClick=${handleFlip} style=${{ zIndex: isFlipped ? 0 : 10 }}
          className=${`absolute inset-0 w-full h-full backface-hidden bg-emerald-100 rounded-[2.5rem] shadow-2xl border border-emerald-200 flex flex-col p-8 sm:p-10 cursor-pointer transition-opacity duration-300 ${isFlipped ? 'opacity-0' : 'opacity-100'}`}>
          <div className="absolute top-0 right-0 p-8 text-emerald-900 opacity-5 pointer-events-none">
            <${Lucide.BrainCircuit} size=${180} />
          </div>
          <div className="flex justify-between items-start relative z-30">
            <div className="bg-emerald-900/10 p-2.5 rounded-xl text-emerald-900">
              <${Lucide.BrainCircuit} size=${28} />
            </div>
            <button onClick=${(e) => handleAction(e, onToggleMastery)}
              className=${`transition-all transform active:scale-95 p-2 rounded-full ${word.mastered ? 'text-emerald-700' : 'text-emerald-900/20'}`}>
              <${Lucide.CheckCircle2} size=${44} />
            </button>
          </div>
          <div className="flex-1 flex flex-col items-center justify-center text-center px-4 z-10">
            ${word.chinese.split('\n').map((line, i) => html`
              <p key=${i} className=${i === 0 ? "text-3xl sm:text-5xl font-extrabold text-slate-900 mb-2" : "text-lg sm:text-2xl font-medium text-slate-700 opacity-80 border-t border-emerald-900/10 pt-2 mt-2"}>
                ${line}
              </p>
            `)}
          </div>
          <div className="text-center text-emerald-900/40 text-xs font-bold z-10 tracking-widest uppercase">Tap to reveal english</div>
        </div>

        <!-- 反面: 英文 -->
        <div onClick=${handleFlip} style=${{ zIndex: isFlipped ? 10 : 0 }}
          className=${`absolute inset-0 w-full h-full backface-hidden bg-indigo-600 rounded-[2.5rem] shadow-2xl border-2 border-indigo-500 flex flex-col p-8 sm:p-10 rotate-y-180 text-white cursor-pointer transition-opacity duration-300 ${isFlipped ? 'opacity-100' : 'opacity-0'}`}>
          <div className="absolute top-0 right-0 p-8 text-white opacity-10 pointer-events-none">
            <${Lucide.BrainCircuit} size=${180} />
          </div>
          <div className="flex justify-between items-start relative z-30">
            <div className="bg-white/20 p-2.5 rounded-xl text-white"><${Lucide.BrainCircuit} size=${28} /></div>
            <button onClick=${(e) => handleAction(e, onToggleMastery)}
              className=${`transition-all transform active:scale-95 p-2 rounded-full ${word.mastered ? 'text-green-300' : 'text-white/30'}`}>
              <${Lucide.CheckCircle2} size=${44} />
            </button>
          </div>
          <div className="flex-1 flex flex-col items-center justify-center text-center px-2 z-10">
            <h3 className=${`font-extrabold tracking-tight mb-8 leading-tight break-words px-4 ${getFontSize(word.english)}`}>${word.english}</h3>
            <button onClick=${(e) => handleAction(e, () => SpeechControl.speak(word.english, settings.voiceURI, settings.speechRate))}
              className="p-6 sm:p-8 bg-white/20 hover:bg-white/30 rounded-full transition-all active:scale-90 shadow-lg relative z-40 border border-white/20">
              <${Lucide.Volume2} size=${44} />
            </button>
          </div>
          <div className="text-center text-indigo-100 text-xs font-bold z-10 tracking-widest uppercase">Tap to go back</div>
        </div>
      </div>
    </div>
  `;
};

/**
 * --- 3. 容器组件 ---
 */
const FlashCardContainer = ({ words, settings, onToggleMastery, onGoToInput, onLoadDefault }) => {
  const [currentIndex, setCurrentIndex] = useState(0);

  const displayWords = useMemo(() => {
    return settings.hideMastered ? words.filter(w => !w.mastered) : words;
  }, [words, settings.hideMastered]);

  const currentWord = displayWords[currentIndex];

  const handleNext = () => setCurrentIndex(c => (c < displayWords.length - 1 ? c + 1 : 0));
  const handlePrev = () => setCurrentIndex(c => (c > 0 ? c - 1 : displayWords.length - 1));

  if (words.length === 0) return html`
    <div className="flex flex-col items-center justify-center gap-8 py-20 px-6">
      <div className="w-32 h-32 bg-indigo-100 text-indigo-600 rounded-full flex items-center justify-center shadow-inner"><${Lucide.PlusCircle} size=${64} strokeWidth=${1.5} /></div>
