      </div>
      <div className="flex flex-col sm:flex-row gap-4 w-full max-w-sm">
        <button onClick=${onLoadDefault} className="flex-1 px-8 py-4 bg-white text-indigo-600 border-2 border-indigo-600 rounded-2xl font-bold shadow-lg hover:bg-indigo-50 active:scale-95 transition-all">默认词库</button>
        <button onClick=${onGoToInput} className="flex-1 px-8 py-4 bg-indigo-600 text-white rounded-2xl font-bold shadow-xl hover:bg-indigo-700 active:scale-95 transition-all">导入单词</button>
      </div>
    </div>
  `;

  if (displayWords.length === 0) return html`<div className="text-center py-20"><h2 className="text-2xl font-bold text-slate-700">🎉 已背完所有标记单词！</h2><button onClick=${onGoToInput} className="mt-4 text-indigo-600 underline">添加更多</button></div>`;

  return html`
    <div className="w-full max-w-4xl flex flex-col items-center gap-10 animate-in fade-in duration-700">
      <div className="w-full flex items-center justify-between px-2 sm:px-12 relative">
        <button onClick=${handlePrev} className="p-4 bg-white hover:bg-slate-50 rounded-full shadow-lg border-2 border-slate-100 z-20 active:scale-90 transition-all text-slate-600"><${Lucide.ChevronLeft} size=${32} /></button>
        <div className="flex-1 max-w-md mx-2">
          <${FlashCard} word=${currentWord} settings=${settings} onToggleMastery=${() => onToggleMastery(currentWord.id)} />
        </div>
        <button onClick=${handleNext} className="p-4 bg-white hover:bg-slate-50 rounded-full shadow-lg border-2 border-slate-100 z-20 active:scale-90 transition-all text-slate-600"><${Lucide.ChevronRight} size=${32} /></button>
      </div>
      <div className="flex flex-col items-center gap-3">
        <div className="text-xs font-bold tracking-widest text-slate-400 uppercase">Step <span className="text-indigo-600">${currentIndex + 1}</span> of ${displayWords.length}</div>
        <div className="w-56 h-2 bg-slate-200 rounded-full overflow-hidden shadow-inner">
          <div className="h-full bg-indigo-600 transition-all duration-500 ease-out" style=${{ width: `${((currentIndex + 1) / displayWords.length) * 100}%` }} />
        </div>
      </div>
    </div>
  `;
};

/**
 * --- 4. 导入/文本框组件 ---
 */
const WordInput = ({ initialWords, onSave }) => {
  const [text, setText] = useState(initialWords.map(w => `${w.english} - ${w.chinese.replace(/\n/g, ' | ')}`).join('\n'));

  const handleSave = () => {
    const lines = text.split('\n').filter(l => l.trim().length > 0);
    const newWords = lines.map((line, index) => {
      const parts = line.split('-').map(s => s.trim());
      const english = parts[0] || 'Empty';
      const chinese = parts.slice(1).join('-').replace(/\s*\|\s*/g, '\n') || '无解释';
      const existing = initialWords.find(w => (w.english||'').toLowerCase() === english.toLowerCase());
      return { 
        id: existing?.id || `word-${Date.now()}-${index}`, 
        english, 
        chinese, 
        mastered: existing?.mastered || false 
      };
    });
    onSave(newWords);
  };

  return html`
    <div className="w-full max-w-3xl flex flex-col gap-6 animate-in slide-in-from-bottom-6 duration-500 px-4">
      <div className="bg-white p-6 sm:p-10 rounded-[2.5rem] shadow-2xl border border-slate-100">
