          </div>
          <button onClick=${handleSave} className="w-full sm:w-auto flex items-center justify-center gap-2 px-8 py-4 bg-indigo-600 text-white font-bold rounded-2xl shadow-xl shadow-indigo-100 hover:bg-indigo-700 active:scale-95 transition-all">
            <${Lucide.Save} size=${20} />保存并学习
          </button>
        </div>
        <textarea 
          value=${text} 
          onChange=${(e) => setText(e.target.value)} 
          placeholder="apple - 苹果 | 健康的红果子" 
          className="w-full h-96 p-8 text-lg bg-slate-50 border-2 border-slate-100 rounded-3xl focus:border-indigo-500 focus:ring-4 focus:ring-indigo-50 outline-none resize-none font-mono transition-all" 
        />
      </div>
    </div>
  `;
};

