import React, { useState, useEffect } from 'react';
import htm from 'htm';
import * as Lucide from 'lucide-react';
import FlashCardContainer from './components/FlashCardContainer.js';
import WordInput from './components/WordInput.js';
import SettingsPanel from './components/SettingsPanel.js';
import { getAvailableVoices } from './utils/speech.js';

const html = htm.bind(React.createElement);

const App = () => {
  const [view, setView] = useState('LEARN');
  const [words, setWords] = useState([]);
  const [settings, setSettings] = useState({ speechRate: 1.0, voiceURI: '', hideMastered: false });

  // 持久化加载
  useEffect(() => {
    const savedWords = localStorage.getItem('smart_vocab_words_v3');
    const savedSettings = localStorage.getItem('smart_vocab_settings_v3');
    if (savedWords) setWords(JSON.parse(savedWords));
    if (savedSettings) {
      setSettings(JSON.parse(savedSettings));
    }
  }, []);

  // 语音初始化逻辑：确保选中推荐列表中的第一个
  useEffect(() => {
    const initializeVoice = () => {
      const voices = getAvailableVoices();
      if (voices.length > 0) {
        // 如果当前没选，或者选的音色已经不在可用列表里了，就自动选第一个优质音色
        const isValid = voices.some(v => v.voiceURI === settings.voiceURI);
        if (!settings.voiceURI || !isValid) {
          setSettings(s => ({ ...s, voiceURI: voices[0].voiceURI }));
        }
      }
    };

    initializeVoice();
    if (window.speechSynthesis) {
      window.speechSynthesis.onvoiceschanged = initializeVoice;
    }
  }, [settings.voiceURI]);

  useEffect(() => {
    localStorage.setItem('smart_vocab_words_v3', JSON.stringify(words));
    localStorage.setItem('smart_vocab_settings_v3', JSON.stringify(settings));
  }, [words, settings]);

  const toggleMastery = (id) => {
    setWords(prev => prev.map(w => w.id === id ? { ...w, mastered: !w.mastered } : w));
  };

  const loadDefault = async () => {
    try {
      const res = await fetch('./words.md');
      const text = await res.text();
      const defaultWords = text.split('\n')
        .filter(l => l.trim() && l.includes('-'))
        .map((line, i) => {
          const parts = line.split('-').map(s => s.trim());
          const eng = parts[0];
          const chi = parts.slice(1).join('-').replace(/\s*\|\s*/g, '\n');
          return { id: `def-${i}-${Date.now()}`, english: eng, chinese: chi, mastered: false };
        });
      setWords(defaultWords);
    } catch (e) { alert('加载失败'); }
  };

  return html`
    <div className="min-h-screen flex flex-col bg-slate-50 text-slate-900">
      <header className="bg-white/80 backdrop-blur-md border-b px-6 py-4 flex items-center justify-between sticky top-0 z-50">
        <div className="flex items-center gap-3 cursor-pointer" onClick=${() => setView('LEARN')}>
          <div className="bg-indigo-600 p-2 rounded-xl text-white shadow-lg shadow-indigo-100"><${Lucide.BrainCircuit} size=${24} /></div>
          <h1 className="text-xl font-black text-slate-800 hidden sm:block">Smart Vocab</h1>
        </div>
        <nav className="flex gap-1 bg-slate-100 p-1 rounded-2xl border">
          <button onClick=${() => setView('LEARN')} className=${`px-6 py-2 rounded-xl text-sm font-bold transition-all ${view==='LEARN' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-800'}`}>学习</button>
          <button onClick=${() => setView('INPUT')} className=${`px-6 py-2 rounded-xl text-sm font-bold transition-all ${view==='INPUT' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-800'}`}>词库</button>
          <button onClick=${() => setView('SETTINGS')} className=${`px-6 py-2 rounded-xl text-sm font-bold transition-all ${view==='SETTINGS' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-800'}`}>设置</button>
        </nav>
      </header>

      <main className="flex-1 flex flex-col items-center justify-center p-4">
        ${view === 'LEARN' && html`<${FlashCardContainer} words=${words} settings=${settings} onToggleMastery=${toggleMastery} onGoToInput=${() => setView('INPUT')} onLoadDefault=${loadDefault} />`}
        ${view === 'INPUT' && html`<${WordInput} initialWords=${words} onSave=${w => {setWords(w); setView('LEARN');}} />`}
        ${view === 'SETTINGS' && html`<${SettingsPanel} settings=${settings} onUpdateSettings=${setSettings} />`}
      </main>
    </div>
  `;
};

export default App;

import React, { useState, useEffect } from 'react';
import htm from 'htm';
import * as Lucide from 'lucide-react';
import { getAvailableVoices } from '../utils/speech.js';

const html = htm.bind(React.createElement);

const SettingsPanel = ({ settings, onUpdateSettings }) => {
  const [voices, setVoices] = useState([]);

  useEffect(() => {
    const load = () => {
      const availableVoices = getAvailableVoices();
      setVoices(availableVoices);
    };

    load();
    if (window.speechSynthesis) {
      window.speechSynthesis.onvoiceschanged = load;
    }
    return () => { 
      if (window.speechSynthesis) window.speechSynthesis.onvoiceschanged = null; 
    };
  }, []);

  return html`
    <div className="w-full max-w-2xl p-4">
      <div className="bg-white p-10 rounded-[3rem] shadow-xl border">
        <h2 className="text-3xl font-black mb-10 flex items-center gap-4 text-slate-800">
          <span className="p-3 bg-indigo-100 text-indigo-600 rounded-2xl"><${Lucide.Sliders} /></span>
          偏好设置
        </h2>

        <div className="space-y-10">
          <!-- 语音选择 -->
          <section className="space-y-4">
            <label className="text-sm font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
              <${Lucide.Globe} size=${16} /> 推荐音色 (英文)
            </label>
            <div className="relative">
              <select 
                value=${settings.voiceURI} 
                onChange=${e => onUpdateSettings({...settings, voiceURI: e.target.value})} 
                className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl outline-none focus:border-indigo-500 transition-all cursor-pointer appearance-none text-slate-700 font-medium"
              >
                ${voices.map(v => html`
                  <option key=${v.voiceURI} value=${v.voiceURI}>
                    ${v.name.replace(/Microsoft |Google |Apple /g, '')} (${v.lang})
                  </option>
                `)}
              </select>
              <div className="absolute right-5 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400">
                <${Lucide.ChevronDown} size=${20} />
              </div>
            </div>
          </section>

          <!-- 语速控制 -->
          <section className="space-y-4">
            <div className="flex justify-between items-center">
              <label className="text-sm font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
                <${Lucide.Zap} size=${16} /> 朗读语速
              </label>
              <span className="px-3 py-1 bg-indigo-50 text-indigo-600 rounded-lg font-black">${settings.speechRate.toFixed(1)}x</span>
            </div>
            <input 
              type="range" min="0.5" max="2" step="0.1" 
              value=${settings.speechRate} 
              onChange=${e => onUpdateSettings({...settings, speechRate: parseFloat(e.target.value)})} 
              className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-indigo-600" 
            />
          </section>

          <!-- 过滤选项 -->
          <section className="pt-8 border-t border-slate-100 flex justify-between items-center">
            <div className="space-y-1">
              <span className="font-bold text-slate-700 flex items-center gap-2">
                <${Lucide.EyeOff} size=${18} /> 自动过滤已记住单词
              </span>
            </div>
            <label className="relative inline-flex items-center cursor-pointer">
              <input 
                type="checkbox" 
                checked=${settings.hideMastered} 
                onChange=${e => onUpdateSettings({...settings, hideMastered: e.target.checked})} 
                className="sr-only peer"
              />
              <div className="w-12 h-7 bg-slate-200 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[4px] after:left-[4px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-indigo-600"></div>
            </label>
          </section>
        </div>
      </div>
    </div>
  `;
};

export default SettingsPanel;

export const getAvailableVoices = () => {
  if (typeof window === 'undefined' || !window.speechSynthesis) return [];

  // 获取所有音色，过滤掉包含 "Default" 字样的系统占位符（如果存在）
  const allVoices = window.speechSynthesis.getVoices().filter(v => !v.name.toLowerCase().includes('default'));

  // 仅保留英文音色
  const enVoices = allVoices.filter(v => v.lang.startsWith('en'));

  // 优质音色关键词匹配
  const premiumKeywords = ['jenny', 'ana', 'sonia', 'samantha', 'google us', 'apple', 'natural'];
  const premium = enVoices.filter(v => premiumKeywords.some(k => v.name.toLowerCase().includes(k)));

  // 优先返回优质音色，否则返回所有英文音色
  return premium.length > 0 ? premium : enVoices;
};

export const speak = (text, voiceURI, rate) => {
  if (!window.speechSynthesis) return;
  window.speechSynthesis.cancel();
  const utterance = new SpeechSynthesisUtterance(text);
  const voices = window.speechSynthesis.getVoices();
  const selectedVoice = voices.find(v => v.voiceURI === voiceURI);
  if (selectedVoice) utterance.voice = selectedVoice;
  utterance.rate = rate || 1.0;
  utterance.lang = 'en-US';
  window.speechSynthesis.speak(utterance);
};

import React, { useState, useEffect, useCallback } from 'react';
import htm from 'htm';
import * as Lucide from 'lucide-react';
import { speak } from '../utils/speech.js';

const html = htm.bind(React.createElement);

const FlashCard = ({ word, settings, onToggleMastery }) => {
  const [isFlipped, setIsFlipped] = useState(false);
