        <div onClick=${handleFlip} style=${{ zIndex: isFlipped ? 0 : 10 }}
          className=${`absolute inset-0 w-full h-full backface-hidden bg-emerald-100 rounded-[2.5rem] shadow-2xl border border-emerald-200 flex flex-col p-8 cursor-pointer overflow-hidden transition-opacity duration-300 ${isFlipped ? 'opacity-0' : 'opacity-100'}`}>

          <!-- 背景装饰大图标 -->
          <div className="absolute -right-12 -bottom-12 text-emerald-900/5 pointer-events-none z-0">
            <${Lucide.BrainCircuit} size=${240} strokeWidth=${1} />
          </div>

          <div className="flex justify-between relative z-30">
            <div className="text-emerald-900/20"><${Lucide.BrainCircuit} size=${32} /></div>
            <button onClick=${(e) => handleAction(e, onToggleMastery)} className=${`p-2 rounded-full transition-all active:scale-125 ${word.mastered ? 'text-emerald-700' : 'text-emerald-900/20'}`}>
              <${Lucide.CheckCircle2} size=${44} />
            </button>
          </div>

          <div className="flex-1 flex flex-col items-center justify-center text-center px-4 relative z-10">
            ${word.chinese.split('\n').map((line, i) => html`
              <p key=${i} className=${i === 0 ? "text-4xl font-black text-slate-900 leading-tight" : "text-xl font-medium text-slate-500 mt-4 border-t border-emerald-200/50 pt-4"}>
                ${line}
              </p>
            `)}
          </div>
        </div>

        <!-- 反面: 英文 -->
        <div onClick=${handleFlip} style=${{ zIndex: isFlipped ? 10 : 0 }}
          className=${`absolute inset-0 w-full h-full backface-hidden bg-indigo-600 rounded-[2.5rem] shadow-2xl border-2 border-indigo-500 flex flex-col p-8 rotate-y-180 text-white cursor-pointer overflow-hidden transition-opacity duration-300 ${isFlipped ? 'opacity-100' : 'opacity-0'}`}>

          <!-- 背景装饰大图标 -->
          <div className="absolute -right-12 -bottom-12 text-white/10 pointer-events-none z-0">
            <${Lucide.BrainCircuit} size=${240} strokeWidth=${1} />
          </div>

          <div className="flex justify-between relative z-30">
            <div className="text-white/20"><${Lucide.BrainCircuit} size=${32} /></div>
            <button onClick=${(e) => handleAction(e, onToggleMastery)} className=${`p-2 rounded-full transition-all active:scale-125 ${word.mastered ? 'text-green-300' : 'text-white/20'}`}>
              <${Lucide.CheckCircle2} size=${44} />
            </button>
          </div>

          <div className="flex-1 flex flex-col items-center justify-center text-center relative z-10">
            <h3 className="text-5xl font-black mb-10 break-words px-4 tracking-tight">${word.english}</h3>
            <button onClick=${(e) => handleAction(e, () => speak(word.english, settings.voiceURI, settings.speechRate))}
              className="p-8 bg-white/20 hover:bg-white/30 rounded-full transition-all active:scale-90 shadow-xl border border-white/20 group">
              <${Lucide.Volume2} size=${44} className="group-hover:scale-110 transition-transform" />
            </button>
          </div>
        </div>
      </div>
    </div>
  `;
};

export default FlashCard;

