            id: `def-${i}-${Date.now()}`, 
            english: eng, 
            chinese: chi, 
            mastered: false,
            unit: currentUnit 
          });
        }
      });
      setWords(defaultWords);
    } catch (e) { alert('加载失败'); }
  };

  return html`
