import { GoogleGenAI, Modality } from "@google/genai";

// 基础 Base64 解码 (不使用外部库)
function decodeBase64(base64) {
  const binaryString = atob(base64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

// 原始 PCM 解码为 AudioBuffer
async function decodeAudioData(data, ctx, sampleRate = 24000, numChannels = 1) {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export const getAvailableVoices = () => {
  if (typeof window === 'undefined' || !window.speechSynthesis) return [];

  const allVoices = window.speechSynthesis.getVoices();
  // 过滤出英文音色，并标记品质
  return allVoices
    .filter(v => v.lang.startsWith('en'))
    .map(v => {
      const uri = v.voiceURI.toLowerCase();
      const isEnhanced = uri.includes('premium') || uri.includes('enhanced') || (!uri.includes('compact') && uri.includes('samantha'));
      return {
        ...v,
        isEnhanced,
        displayName: `${v.name.replace(/Microsoft |Google |Apple /g, '')}${isEnhanced ? ' (✨ 高级版)' : ''}`
      };
    })
    .sort((a, b) => (b.isEnhanced ? 1 : 0) - (a.isEnhanced ? 1 : 0)); // 高级音色排在前面
};

// 全局音频上下文，延迟初始化以符合浏览器政策
let audioCtx = null;

export const speak = async (text, settings) => {
  const { engine = 'SYSTEM', voiceURI, speechRate = 1.0, aiVoice = 'Kore' } = settings;

  // 模式 1: Gemini AI 语音引擎 (最高品质)
  if (engine === 'AI') {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text: `Pronounce clearly: ${text}` }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: {
              prebuiltVoiceConfig: { voiceName: aiVoice },
            },
          },
        },
      });

      const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (base64Audio) {
        if (!audioCtx) audioCtx = new (window.AudioContext || window.webkitAudioContext)({ sampleRate: 24000 });
        const bytes = decodeBase64(base64Audio);
        const buffer = await decodeAudioData(bytes, audioCtx);
        const source = audioCtx.createBufferSource();
        source.buffer = buffer;
        source.playbackRate.value = speechRate;
        source.connect(audioCtx.destination);
        source.start();
        return;
      }
    } catch (error) {
      console.error("AI 发音失败，降级到系统语音:", error);
    }
  }

  // 模式 2: 系统原生语音 (Samantha 等)
  if (!window.speechSynthesis) return;
  window.speechSynthesis.cancel();
  const utterance = new SpeechSynthesisUtterance(text);
  const voices = window.speechSynthesis.getVoices();
  const selectedVoice = voices.find(v => v.voiceURI === voiceURI);
  if (selectedVoice) utterance.voice = selectedVoice;
  utterance.rate = speechRate;
  utterance.lang = 'en-US';
  window.speechSynthesis.speak(utterance);
};

