import { GoogleGenAI, Modality } from "@google/genai";

// 辅助函数：解码 Base64 为 Uint8Array
function decodeBase64(base64) {
  const binaryString = atob(base64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

// 辅助函数：将 PCM 数据转换为 AudioBuffer
async function decodePCM(data, ctx) {
  const dataInt16 = new Int16Array(data.buffer);
  const buffer = ctx.createBuffer(1, dataInt16.length, 24000);
  const channelData = buffer.getChannelData(0);
  for (let i = 0; i < dataInt16.length; i++) {
    channelData[i] = dataInt16[i] / 32768.0;
  }
  return buffer;
}

export const getAvailableVoices = () => {
  if (typeof window === 'undefined' || !window.speechSynthesis) return [];
  const allVoices = window.speechSynthesis.getVoices();

  // 本地引擎音色
  let enVoices = allVoices.filter(v => v.lang.startsWith('en'));
  const recommendedNames = ['samantha', 'jenny', 'aria', 'guy', 'sarah', 'daniel'];

  let filtered = enVoices.filter(v => {
    const name = v.name.toLowerCase();
    const uri = (v.voiceURI || '').toLowerCase();
    return recommendedNames.some(rec => name.includes(rec)) && !name.includes('compact');
  });

  if (filtered.length === 0) filtered = enVoices;

  const localVoices = filtered.sort((a, b) => {
    if (a.name === b.name) return (b.voiceURI || '').length - (a.voiceURI || '').length;
    return a.name.localeCompare(a.name);
  });

  // 模拟一个 Gemini 虚拟音色项，用于 UI 显示
  return [
    { name: "✨ Gemini Pro (Cloud AI)", voiceURI: "GEMINI_CLOUD", lang: "en-US", isGemini: true },
    ...localVoices
  ];
};

let audioCtx = null;

export const speak = async (text, voiceURI, rate) => {
  if (voiceURI === 'GEMINI_CLOUD') {
    try {
      // 1. 初始化 AI
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      // 2. 请求语音合成
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text: `Read this clearly: ${text}` }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
          },
        },
      });

      const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (!base64Audio) throw new Error("No audio data");

      // 3. 播放逻辑
      if (!audioCtx) audioCtx = new (window.AudioContext || window.webkitAudioContext)();
      const bytes = decodeBase64(base64Audio);
      const buffer = await decodePCM(bytes, audioCtx);

      const source = audioCtx.createBufferSource();
      source.buffer = buffer;
      source.playbackRate.value = rate || 1.0;
      source.connect(audioCtx.destination);
      source.start();
      return true;
    } catch (e) {
      console.warn("Gemini TTS Failed, falling back to local:", e);
      // 如果 Gemini 失败（比如地区限制），回退到本地 Samantha 音色
      const localFallback = window.speechSynthesis.getVoices().find(v => v.name.toLowerCase().includes('samantha')) || 
                          window.speechSynthesis.getVoices().find(v => v.lang.startsWith('en'));
      speakLocal(text, localFallback?.voiceURI, rate);
    }
  } else {
    speakLocal(text, voiceURI, rate);
  }
};

function speakLocal(text, voiceURI, rate) {
  if (!window.speechSynthesis) return;
  window.speechSynthesis.cancel();
  const utterance = new SpeechSynthesisUtterance(text);
  const voices = window.speechSynthesis.getVoices();
  const selectedVoice = voices.find(v => v.voiceURI === voiceURI);
  if (selectedVoice) utterance.voice = selectedVoice;
  utterance.rate = rate || 1.0;
  utterance.lang = 'en-US';
  window.speechSynthesis.speak(utterance);
}

