                  value=${settings.geminiApiKey || ''}
                  onChange=${e => onUpdateSettings({...settings, geminiApiKey: e.target.value})}
                  className="w-full pl-12 pr-12 py-4 bg-white border border-slate-200 rounded-2xl focus:ring-4 focus:ring-indigo-100 outline-none font-mono text-sm transition-all"
                />
                <div className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400">
                  <${Lucide.Key} size=${18} />
                </div>
                <button 
                  onClick=${() => setShowKey(!showKey)}
                  className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600 transition-colors"
                >
                  <${showKey ? Lucide.EyeOff : Lucide.Eye} size=${18} />
                </button>
              </div>
              <p className="text-[11px] text-slate-400 leading-relaxed px-2">
                <${Lucide.Info} size=${12} className="inline mr-1 mb-0.5" />
                Key 仅存储在您的浏览器本地，不会上传至第三方。
              </p>
            </div>
          </section>

          <!-- 朗读音色 -->
          <section className="space-y-4">
            <label className="text-sm font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
              <${Lucide.Globe} size=${16} /> 朗读音色
            </label>
            <div className="grid grid-cols-1 gap-2 max-h-60 overflow-y-auto pr-2 custom-scrollbar">
              ${voices.map(v => {
                const isSelected = settings.voiceURI === v.voiceURI;
                const requiresKey = v.isGemini && !settings.geminiApiKey;
                return html`
                  <button 
                    key=${v.voiceURI}
                    onClick=${() => onUpdateSettings({...settings, voiceURI: v.voiceURI})}
                    className=${`flex items-center justify-between p-4 rounded-2xl border-2 transition-all text-left ${
                      isSelected 
                        ? 'border-indigo-600 bg-indigo-50 shadow-sm' 
                        : 'border-slate-50 bg-slate-50 hover:border-slate-200'
                    }`}
                  >
                    <div className="flex items-center gap-3 overflow-hidden">
                      <div className=${`p-2 rounded-lg ${v.isGemini ? 'bg-amber-100 text-amber-600' : 'bg-white text-slate-400'}`}>
                        <${v.isGemini ? Lucide.Sparkles : Lucide.User} size=${18} />
                      </div>
                      <div className="flex flex-col">
                        <span className=${`font-bold truncate ${isSelected ? 'text-indigo-700' : 'text-slate-600'}`}>
                          ${v.name.replace(/Microsoft |Google |Apple /g, '')}
                        </span>
                        ${requiresKey && html`<span className="text-[9px] text-amber-600 font-bold uppercase tracking-tighter">需要配置 Key</span>`}
                      </div>
                    </div>
                    ${isSelected && html`<${Lucide.Check} size=${18} className="text-indigo-600 shrink-0" />`}
                  </button>
                `;
              })}
            </div>
          </section>

          <!-- 语速控制 -->
          <section className="space-y-4">
            <div className="flex justify-between items-center">
              <label className="text-sm font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
                <${Lucide.Zap} size=${16} /> 语速控制
              </label>
              <span className="px-3 py-1 bg-indigo-50 text-indigo-600 rounded-lg font-black">${settings.speechRate.toFixed(1)}x</span>
            </div>
            <input 
              type="range" min="0.5" max="2" step="0.1" 
              value=${settings.speechRate} 
              onChange=${e => onUpdateSettings({...settings, speechRate: parseFloat(e.target.value)})} 
              className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-indigo-600" 
            />
          </section>

          <!-- 学习偏好 -->
          <section className="pt-8 border-t border-slate-100 flex justify-between items-center">
            <span className="font-bold text-slate-700 flex items-center gap-2">
              <${Lucide.EyeOff} size=${18} /> 隐藏已记住单词
            </span>
            <label className="relative inline-flex items-center cursor-pointer">
              <input 
                type="checkbox" 
                checked=${settings.hideMastered} 
                onChange=${e => onUpdateSettings({...settings, hideMastered: e.target.checked})} 
                className="sr-only peer"
              />
              <div className="w-12 h-7 bg-slate-200 rounded-full peer peer-checked:bg-indigo-600 transition-colors after:content-[''] after:absolute after:top-[4px] after:left-[4px] after:bg-white after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:after:translate-x-full"></div>
            </label>
          </section>
        </div>
      </div>
    </div>
  `;
};

export default SettingsPanel;
